+#[must_use]
+fn segment_start_before_flag(command: &str, flag_start: usize) -> usize {
+    let bytes = command.as_bytes();
+    let mut i = flag_start.min(bytes.len());
+
+    while i > 0 {
+        i -= 1;
+        match bytes[i] {
+            b'|' => {
+                if i > 0 && bytes[i - 1] == b'|' {
+                    return i + 1;
+                }
